#include "jayess_runtime.h"
#include <cubeb/cubeb.h>
#include <stdint.h>

static void jayess_audio_context_finalize(void *handle) {
    if (handle != NULL) {
        cubeb_destroy((cubeb *) handle);
    }
}

jayess_value *jayess_audio_create_context(jayess_value *name_value, jayess_value *backend_value) {
    const char *name = NULL;
    const char *backend = NULL;
    cubeb * context = NULL;
    int rv = 0;

    if (name_value != NULL && !jayess_value_is_nullish(name_value)) {
        name = jayess_expect_string(name_value, "jayess_audio_create_context");
        if (jayess_has_exception()) {
            return jayess_value_undefined();
        }
    }
    if (backend_value != NULL && !jayess_value_is_nullish(backend_value)) {
        backend = jayess_expect_string(backend_value, "jayess_audio_create_context");
        if (jayess_has_exception()) {
            return jayess_value_undefined();
        }
    }
    rv = cubeb_init(&context, name, backend);
    if (rv != CUBEB_OK || context == NULL) {
        return jayess_value_undefined();
    }
    return jayess_value_from_managed_native_handle("CubebContext", context, jayess_audio_context_finalize);
}

jayess_value *jayess_audio_destroy_context(jayess_value *context_value) {
    return jayess_value_from_bool(jayess_value_close_native_handle(context_value));
}

jayess_value *jayess_audio_backend_id(jayess_value *context_value) {
    cubeb * context = (cubeb *) jayess_expect_native_handle(context_value, "CubebContext", "jayess_audio_backend_id");
    const char * backend = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    backend = cubeb_get_backend_id(context);
    if (backend == NULL) {
        return jayess_value_undefined();
    }
    return jayess_value_from_string(backend);
}

jayess_value *jayess_audio_max_channel_count(jayess_value *context_value) {
    cubeb * context = (cubeb *) jayess_expect_native_handle(context_value, "CubebContext", "jayess_audio_max_channel_count");
    uint32_t max_channels = 0;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (cubeb_get_max_channel_count(context, &max_channels) != CUBEB_OK) {
        return jayess_value_undefined();
    }
    return jayess_value_from_number((double) max_channels);
}
